import json
import urllib3

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    if 'x-enrich-url' in headers:
        url = headers['x-enrich-url'][0]['value']
        
        http = urllib3.PoolManager()
        r = http.request('GET', url)
        
        data = json.loads(r.data.decode('utf-8'))  # assuming the response is in JSON format
        
        request['querystring'] = {**request['querystring'], **data}  
    
    return request